Below is a complete, self-contained HTML file that implements your request. It visualizes binary search on a sorted array displayed as numbered boxes. Here's a quick overview of what it does:

- **Array Display**: A sorted array (e.g., [1, 3, 5, 7, 9, 11, 13, 15]) is shown as a row of boxes.
- **Target Input**: A text input field where you can enter a number to search for.
- **Step Button**: When clicked, it performs one step of the binary search algorithm:
  - It highlights the current search range (low to high) in yellow.
  - It highlights the middle element in red.
  - It updates a status message to show what's happening (e.g., "Too high, new high: 3").
- **End of Search**: Once the search is complete, it displays whether the target was found (and at what index) or not found.
- **Reset**: If you want to run another search, simply refresh the page.

This is all contained in a single HTML file with embedded CSS and JavaScript. You can copy and paste the code below into a file (e.g., `binary-search-visualizer.html`) and open it in a web browser to try it out.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Binary Search Visualizer</title>
    <style>
        /* Styles for the array boxes */
        #array-container {
            margin: 20px 0;
            text-align: center;
        }

        .box {
            display: inline-block;
            width: 50px;
            height: 50px;
            margin: 5px;
            border: 1px solid black;
            background-color: white;
            text-align: center;
            line-height: 50px;
            font-family: Arial, sans-serif;
            font-size: 16px;
            transition: background-color 0.3s ease; /* Smooth highlight transition */
        }

        /* Highlight for the search range (low to high) */
        .highlight-range {
            background-color: yellow;
        }

        /* Highlight for the middle element */
        .highlight-middle {
            background-color: red; /* Overrides range highlight for middle */
        }

        /* General styles */
        body {
            font-family: Arial, sans-serif;
            text-align: center;
            margin: 20px;
        }

        #status {
            margin-top: 20px;
            font-size: 18px;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <h1>Binary Search Visualizer</h1>
    <p>Enter a target number to search in the sorted array: [1, 3, 5, 7, 9, 11, 13, 15]</p>
    <input type="number" id="target-input" placeholder="e.g., 7">
    <button id="step-button">Start/Next Step</button>
    <div id="array-container"></div>
    <div id="status"></div>

    <script>
        // The sorted array to visualize
        const array = [1, 3, 5, 7, 9, 11, 13, 15];

        // State variables
        let low = 0;
        let high = array.length - 1;
        let target = null;
        let found = false;

        document.addEventListener('DOMContentLoaded', () => {
            const arrayContainer = document.getElementById('array-container');

            // Create and append boxes for each element in the array
            array.forEach((num, index) => {
                const box = document.createElement('div');
                box.className = 'box';
                box.textContent = num;
                box.dataset.index = index;  // Store index for reference
                arrayContainer.appendChild(box);
            });

            const stepButton = document.getElementById('step-button');
            stepButton.addEventListener('click', performStep);
        });

        function performStep() {
            const statusDiv = document.getElementById('status');

            if (target === null) {
                // First click: Get the target from input
                target = parseInt(document.getElementById('target-input').value);
                if (isNaN(target)) {
                    statusDiv.textContent = 'Please enter a valid number.';
                    return;
                }
                low = 0;  // Reset low
                high = array.length - 1;  // Reset high
                found = false;  // Reset found flag
                statusDiv.textContent = `Searching for ${target}...`;
            } else if (low <= high && !found) {
                // Perform one step of binary search
                const mid = Math.floor((low + high) / 2);

                // Highlight the range (low to high)
                highlightRange(low, high);

                // Highlight the middle element
                highlightMiddle(mid);

                if (array[mid] === target) {
                    found = true;
                    statusDiv.textContent = `Found ${target} at index ${mid}!`;
                    // Optionally, keep the middle highlighted
                    document.querySelectorAll('.box').forEach(box => {
                        if (parseInt(box.dataset.index) === mid) {
                            box.classList.add('highlight-middle');  // Permanent highlight for found
                        }
                    });
                } else if (array[mid] > target) {
                    high = mid - 1;
                    statusDiv.textContent = `Too high: ${array[mid]} > ${target}. New high: ${high}`;
                } else {
                    low = mid + 1;
                    statusDiv.textContent = `Too low: ${array[mid]} < ${target}. New low: ${low}`;
                }
            } else if (!found) {
                // Search completed, not found
                statusDiv.textContent = `${target} not found in the array.`;
            }
        }

        function highlightRange(lowIndex, highIndex) {
            const boxes = document.querySelectorAll('.box');
            boxes.forEach((box, index) => {
                const boxIndex = parseInt(box.dataset.index);
                if (boxIndex >= lowIndex && boxIndex <= highIndex) {
                    box.classList.add('highlight-range');
                } else {
                    box.classList.remove('highlight-range', 'highlight-middle');  // Remove previous highlights
                }
            });
        }

        function highlightMiddle(midIndex) {
            const boxes = document.querySelectorAll('.box');
            boxes.forEach(box => {
                const boxIndex = parseInt(box.dataset.index);
                if (boxIndex === midIndex) {
                    box.classList.add('highlight-middle');
                } else {
                    box.classList.remove('highlight-middle');  // Remove from others
                }
            });
        }
    </script>
</body>
</html>
```

### How to Use:
1. Save the code to a file named `binary-search-visualizer.html`.
2. Open the file in a web browser.
3. Enter a number in the input field (e.g., 7) and click the "Start/Next Step" button.
4. Each click of the button will:
   - Advance the binary search by one step.
   - Highlight the current search range in yellow.
   - Highlight the middle element in red.
   - Update the status message.
5. When the search ends, it will show if the target was found or not.

This implementation is straightforward and educational. If you'd like any modifications (e.g., changing the array, adding more features like automatic stepping, or customizing the styles), just let me know—I'm here to help! 😊

Below is a complete, self-contained HTML file that visualizes binary search on a sorted array. The array is displayed as a series of numbered boxes. Here's a quick overview of what it includes:

- **Array Display**: A sorted array (e.g., [1, 3, 5, 7, 9, 11, 13, 15]) shown as boxes.
- **Input Field**: A text input where you can enter a target number to search for.
- **Step Button**: When clicked, it advances the binary search one step at a time, highlighting the current search range (low and high indices) and the middle element.
- **Visualization Feedback**: 
  - The boxes for the low and high indices are highlighted in blue and red, respectively.
  - The middle element is highlighted in yellow.
  - After each step, a message updates to show the current state (e.g., "Searching... Mid = 7").
