You can copy the entire code below into a file (e.g., `binary_search_visualizer.html`) and open it in a web browser to try it out. I'm glad to help—let me know if you'd like any modifications!

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Binary Search Visualizer</title>
    <style>
        /* Basic styling for the page */
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
            text-align: center;
        }

        /* Container for the array boxes */
        #array-container {
            display: flex;
            justify-content: center;
            margin: 20px auto;
            width: 80%;
            flex-wrap: wrap;
        }

        /* Individual boxes for array elements */
        .box {
            width: 50px;
            height: 50px;
            border: 1px solid #000;
            margin: 5px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
            background-color: #f0f0f0; /* Default background */
            transition: background-color 0.3s; /* Smooth highlight transition */
        }

        /* Highlight classes */
        .highlight-low {
            background-color: blue; /* Highlight for low index */
            color: white;
        }

        .highlight-high {
            background-color: red; /* Highlight for high index */
            color: white;
        }

        .highlight-mid {
            background-color: yellow; /* Highlight for middle index */
        }

        /* Status message */
        #status {
            margin: 20px;
            font-size: 18px;
            color: green;
        }

        /* Input and button styling */
        #controls {
            margin: 20px;
        }

        input, button {
            padding: 10px;
            font-size: 16px;
            margin: 5px;
        }
    </style>
</head>
<body>
    <h1>Binary Search Visualizer</h1>
    <p>Enter a target number and click "Step" to visualize the binary search on the array: [1, 3, 5, 7, 9, 11, 13, 15]</p>

    <div id="controls">
        <label for="target-input">Target: </label>
        <input type="number" id="target-input" placeholder="e.g., 7">
        <button id="step-button">Step</button>
    </div>

    <div id="array-container">
        <!-- Array boxes will be generated here by JavaScript -->
    </div>

    <div id="status">Ready to search!</div>

    <script>
        // Sorted array to visualize
        const array = [1, 3, 5, 7, 9, 11, 13, 15];
        let low = 0;
        let high = array.length - 1;
        let mid = null;
        let target = null;
        let isSearching = false; // Flag to track if search is in progress

        // Function to render the array boxes
        function renderArray() {
            const container = document.getElementById('array-container');
            container.innerHTML = ''; // Clear existing boxes
            array.forEach((value, index) => {
                const box = document.createElement('div');
                box.className = 'box';
                box.textContent = value;
                box.dataset.index = index; // Store index for reference
                container.appendChild(box);
            });
            clearHighlights(); // Ensure no highlights on initial render
        }

        // Function to highlight elements
        function highlightElements() {
            clearHighlights(); // Remove previous highlights

            const boxes = document.querySelectorAll('.box');

            if (isSearching) {
                // Highlight low index
                if (low <= high) {
                    boxes[low].classList.add('highlight-low');
                }

                // Highlight high index
                if (high >= low) {
                    boxes[high].classList.add('highlight-high');
                }

                // Highlight mid index if calculated
                if (mid !== null && mid >= low && mid <= high) {
                    boxes[mid].classList.add('highlight-mid');
                }
            }
        }

        // Function to clear all highlights
        function clearHighlights() {
            const boxes = document.querySelectorAll('.box');
            boxes.forEach(box => {
                box.classList.remove('highlight-low', 'highlight-high', 'highlight-mid');
            });
        }

        // Function to perform one step of binary search
        function performStep() {
            const statusDiv = document.getElementById('status');

            if (!isSearching) {
                // Initialize search
                target = parseInt(document.getElementById('target-input').value);
                if (isNaN(target)) {
                    statusDiv.textContent = 'Please enter a valid target number.';
                    return;
                }
                low = 0;
                high = array.length - 1;
                isSearching = true;
                statusDiv.textContent = 'Search started!';
            }

            if (low <= high) {
                mid = Math.floor((low + high) / 2);
                const midValue = array[mid];

                statusDiv.textContent = `Low: ${low}, High: ${high}, Mid: ${mid} (Value: ${midValue})`;

                if (midValue === target) {
                    statusDiv.textContent = `Found! Target ${target} at index ${mid}.`;
                    isSearching = false; // End search
                } else if (midValue < target) {
                    low = mid + 1;
                    statusDiv.textContent += ' - Moving low to ' + low;
                } else {
                    high = mid - 1;
                    statusDiv.textContent += ' - Moving high to ' + high;
                }

                highlightElements(); // Update highlights
            } else {
                statusDiv.textContent = `Not found! Target ${target} is not in the array.`;
                isSearching = false; // End search
                clearHighlights();
            }
        }

        // Event listener for the step button
        document.getElementById('step-button').addEventListener('click', performStep);

        // Initial render
        window.onload = function() {
            renderArray();
        };
    </script>
</body>
</html>
```

