                element.dataset.index = index;  // Store index for reference
                container.appendChild(element);
                arrayElements[index] = element;  // Store for later highlighting
            });
        }

        // Function to highlight elements
        function highlightElements() {
            // Reset all highlights
            arrayElements.forEach(el => {
                el.classList.remove('highlight-range', 'highlight-mid');
            });

            if (isSearching) {
                // Highlight the range (low to high)
                for (let i = low; i <= high; i++) {
                    if (arrayElements[i]) arrayElements[i].classList.add('highlight-range');
                }

                // Highlight the middle element
                if (mid !== null && arrayElements[mid]) {
                    arrayElements[mid].classList.add('highlight-mid');
                }
            }
        }

        // Function to perform one step of binary search
        function stepSearch() {
            if (low > high) {
                // Search ended
                document.getElementById('status').textContent = 'Search complete: Target not found.';
                document.getElementById('result').textContent = 'Not found';
                document.getElementById('step-button').disabled = true;
                isSearching = false;
                return;
            }

            mid = Math.floor((low + high) / 2);
            document.getElementById('status').textContent = `Low: ${low}, High: ${high}, Mid: ${mid}, Value at Mid: ${array[mid]}`;

            if (array[mid] === target) {
                document.getElementById('status').textContent = `Found at index ${mid}!`;
                document.getElementById('result').textContent = `Found at index ${mid}`;
                highlightElements();  // Final highlight
                document.getElementById('step-button').disabled = true;
                isSearching = false;
                return;
            } else if (array[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }

            highlightElements();  // Update highlights for next step
        }

        // Event listeners
        document.getElementById('start-button').addEventListener('click', () => {
            target = parseInt(document.getElementById('target-input').value);
            if (isNaN(target)) {
                alert('Please enter a valid number.');
                return;
            }

            low = 0;
            high = array.length - 1;
            isSearching = true;
            document.getElementById('step-button').disabled = false;
            document.getElementById('status').textContent = 'Search started. Click Step to proceed.';
            document.getElementById('result').textContent = '';
            highlightElements();  // Initial highlight
        });

        document.getElementById('step-button').addEventListener('click', stepSearch);

        document.getElementById('reset-button').addEventListener('click', () => {
            low = 0;
            high = array.length - 1;
            mid = null;
            isSearching = false;
